import json
from flask import Flask, jsonify
from pymemcache.client import base

app = Flask(__name__)

# Memcached client configuration
MEMCACHED_SERVER = ('localhost', 11211)
MEMCACHED_TTL_DB = 60  # seconds for database results
MEMCACHED_TTL_API = 30  # seconds for API responses

# Initialize Memcached client
cache = base.Client(MEMCACHED_SERVER)

# --- Mock Database Interaction ---
# In a real application, this would connect to a database (e.g., PostgreSQL, MySQL)
def _get_user_from_db(user_id):
    """Simulates fetching a user from a database."""
    print(f"Fetching user {user_id} from DB...")
    # Simulate a database lookup delay
    import time
    time.sleep(0.5)
    users_data = {
        1: {"id": 1, "name": "Alice", "email": "alice@example.com", "role": "admin"},
        2: {"id": 2, "name": "Bob", "email": "bob@example.com", "role": "user"},
        3: {"id": 3, "name": "Charlie", "email": "charlie@example.com", "role": "editor"},
    }
    return users_data.get(user_id)

def _get_all_products_from_db():
    """Simulates fetching all products from a database."""
    print("Fetching all products from DB...")
    import time
    time.sleep(0.8)
    return [
        {"id": 101, "name": "Laptop", "price": 1200},
        {"id": 102, "name": "Mouse", "price": 25},
        {"id": 103, "name": "Keyboard", "price": 75},
    ]
# -----------------------------------


@app.route('/')
def index():
    return "Welcome to the Caching Flask App! Try /users/<id> or /products."

@app.route('/users/<int:user_id>')
def get_user(user_id):
    cache_key = f"user_{user_id}"
    
    # Try to get data from cache
    cached_data = cache.get(cache_key)

    if cached_data:
        print(f"Cache HIT for {cache_key}")
        # Memcached stores bytes, decode if original data was string/json
        user_data = json.loads(cached_data.decode('utf-8'))
        return jsonify({"source": "cache", "data": user_data})
    
    print(f"Cache MISS for {cache_key}. Fetching from DB...")
    user_data = _get_user_from_db(user_id)

    if user_data:
        # Store data in cache
        # pymemcache expects bytes for value, so serialize to JSON string and then encode
        cache.set(cache_key, json.dumps(user_data).encode('utf-8'), expire=MEMCACHED_TTL_DB)
        return jsonify({"source": "database", "data": user_data})
    else:
        return jsonify({"message": "User not found"}), 404

@app.route('/products')
def get_products():
    cache_key = "all_products"

    # Try to get data from cache
    cached_data = cache.get(cache_key)

    if cached_data:
        print(f"Cache HIT for {cache_key}")
        products_data = json.loads(cached_data.decode('utf-8'))
        return jsonify({"source": "cache", "data": products_data})

    print(f"Cache MISS for {cache_key}. Fetching from DB...")
    products_data = _get_all_products_from_db()

    # Store data in cache for a shorter TTL as an API response example
    cache.set(cache_key, json.dumps(products_data).encode('utf-8'), expire=MEMCACHED_TTL_API)
    return jsonify({"source": "database", "data": products_data})

@app.route('/clear-cache/<string:key>')
def clear_specific_cache(key):
    """Endpoint to manually clear a specific cache key."""
    result = cache.delete(key)
    if result:
        return jsonify({"message": f"Cache key '{key}' cleared successfully."}), 200
    else:
        return jsonify({"message": f"Cache key '{key}' not found or could not be cleared."}), 404

@app.route('/clear-all-cache')
def clear_all_cache():
    """Endpoint to manually clear all cache entries."""
    # Note: 'flush_all' is a powerful operation that clears everything
    # Use with caution in production environments.
    cache.flush_all()
    return jsonify({"message": "All cache entries cleared successfully."}), 200

